class Solution {
public:
    int longestSubsequence(string s, int k) {
        int n = s.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            int num = 0;
            for (int j = i; j < n; j++) {
                num = num * 2 + (s[j] - '0');
                if (num > k) break;
                res = max(res, j - i + 1);
            }
        }
        return res;
    }
};
